text:
{{(() => {
     if (GeocodeNewPickupAddress.isLoading) return "🔍 Finding location...";
     if (NewPickupLatHidden.text && NewPickupLngHidden.text) return "✅ Location found and validated";
     if (NewPickupAddressInput.text?.length > 3 && !GeocodeNewPickupAddress.isLoading) return "❌ Address not found - please check spelling";
     return "📍 Enter address to find location";
   })()}}

textColor:
{{(() => {
     if (GeocodeNewPickupAddress.isLoading) return "#F59E0B";
     if (NewPickupLatHidden.text && NewPickupLngHidden.text) return "#10B981";
     if (NewPickupAddressInput.text?.length > 3) return "#EF4444";
     return "#6B7280";
   })()}}
